    def _encode_disk_value(self, value: Any) -> bytes:
        """Pickle `value` and, if compression is enabled, compress and prepend a magic header.

        The header (`b"DSPC"` + a 1-byte codec id) lets `_decode_disk_value` identify the codec
        used, while entries written before this feature existed (which have no header) continue
        to load as plain pickled/deserialized objects via DiskCache's own (de)serialization.
        """
        payload = pickle.dumps(value)
        codec = _COMPRESS_NAME_TO_CODEC[self.compress]
        if codec == _CODEC_GZIP:
            payload = gzip.compress(payload)
        elif codec == _CODEC_ZLIB:
            payload = zlib.compress(payload)
        return _MAGIC_HEADER + bytes([codec]) + payload

    def _decode_disk_value(self, raw: bytes) -> Any:
        codec = raw[len(_MAGIC_HEADER)]
        payload = raw[len(_MAGIC_HEADER) + 1 :]
        if codec == _CODEC_GZIP:
            payload = gzip.decompress(payload)
        elif codec == _CODEC_ZLIB:
            payload = zlib.decompress(payload)
